I have a smart table that show rows from server using st-pipe to call the "CallServer" method and get paged rows. it work, but I have to implement functionality of add, delete, modify rows. and I need to call the "CallServer" when one of the crud action ended.

How can i get the tableState inside my crud function, so i can pass it to the "Callserver" function to refresh the data and amntain the same order/filter?



    $scope.CallServer = function callServer(tableState) {
      var start = tableState.pagination.start || 0;
      var ItemNumber = tableState.pagination.number || 10;
      var PageIndex = (start / ItemNumber) + 1;

      //Gestione ordinamento
      var ColumnName = "AspNetUserID";
      if (typeof tableState.sort.predicate != 'undefined') {
        ColumnName = tableState.sort.predicate;
      } else {
        tableState.sort.predicate = "AspNetUserID";
      }

      var ColumnSortDirection = 0;
      if (typeof tableState.sort.reverse != 'undefined') {
        ColumnSortDirection = tableState.sort.reverse ? 1 : 0;
      } else {
        tableState.sort.reverse = 0;
      }

      var promise = AccountsService.GetAccountsSqueezed_OST(PageIndex, ItemNumber, ColumnName, ColumnSortDirection);
      promise.then(function (results) {
        $scope.rowCollection = results.data.DataObjectList;
        tableState.pagination.numberOfPages = Math.ceil(results.data.DataObjectTotalCount / ItemNumber);
      });
    };

